import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import axiosInstance from "../api/axios"; 

export default function Register() {
  const navigate = useNavigate();

 
  const [formData, setFormData] = useState({
    username: "", 
    email: "",
    password: "",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
 
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  
  const handleRegister = async (e) => {
    e.preventDefault();  
 
    if (!formData.username || !formData.email || !formData.password) {
      setError("All fields are required.");
      return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      // আপনার ব্যাকএন্ডের রেজিস্টার এন্ডপয়েন্ট (যেমন: api/register/ বা api/users/)
      const response = await axiosInstance.post("api/register/", {
        username: formData.username,
        email: formData.email,
        password: formData.password,
      });

      setSuccess("Registration Successful! Redirecting to login... 🎉");
      
      // ফর্ম ক্লিয়ার করা
      setFormData({ username: "", email: "", password: "" });

      // ২ সেকেন্ড পর ইউজারকে লগইন পেজে পাঠিয়ে দেওয়া
      setTimeout(() => {
        navigate("/"); // আপনার লগইন রাউট যদি '/' হয়
      }, 2000);

    } catch (err) {
      console.error(err);
      // ব্যাকএন্ড থেকে আসা নির্দিষ্ট এরর মেসেজ ক্যাচ করা
      setError(
        err?.response?.data?.detail || 
        err?.response?.data?.message ||
        "Registration failed. Please try again."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-600 via-purple-600 to-pink-500 p-4">
      
     
      <form 
        onSubmit={handleRegister} 
        className="bg-white/10 backdrop-blur-xl p-8 rounded-2xl w-full max-w-md border border-white/20 shadow-2xl"
      >
        <h1 className="text-white text-3xl font-bold text-center">
          Register
        </h1>

       
        {error && (
          <div className="mt-4 bg-red-500/20 border border-red-500/40 text-red-200 px-4 py-2 rounded-lg text-sm font-medium">
            {error}
          </div>
        )}

       
        {success && (
          <div className="mt-4 bg-green-500/20 border border-green-500/40 text-green-200 px-4 py-2 rounded-lg text-sm font-medium">
            {success}
          </div>
        )}

        
        <input 
          type="text"
          name="username"
          value={formData.username}
          onChange={handleChange}
          className="w-full mt-6 p-3 rounded-lg bg-white/20 text-white placeholder-white/60 outline-none focus:ring-2 focus:ring-white/40 transition" 
          placeholder="Username / Name" 
        />
        
        <input 
          type="email"
          name="email"
          value={formData.email}
          onChange={handleChange}
          className="w-full mt-4 p-3 rounded-lg bg-white/20 text-white placeholder-white/60 outline-none focus:ring-2 focus:ring-white/40 transition" 
          placeholder="Email" 
        />
        
        <input 
          type="password"
          name="password"
          value={formData.password}
          onChange={handleChange}
          className="w-full mt-4 p-3 rounded-lg bg-white/20 text-white placeholder-white/60 outline-none focus:ring-2 focus:ring-white/40 transition" 
          placeholder="Password" 
        />

         
        <button 
          type="submit"
          disabled={loading}
          className={`w-full mt-6 bg-white text-black py-3 rounded-lg font-semibold transition ${
            loading ? "bg-gray-300 cursor-not-allowed" : "hover:bg-gray-200"
          }`}
        >
          {loading ? "Registering..." : "Register"}
        </button>

        <p className="text-center text-white/70 text-sm mt-5">
          Already have an account?{" "}
          <Link to="/" className="text-white font-semibold hover:underline">
            Login
          </Link>
        </p>

      </form>
    </div>
  );
}
